commits.content:
*,
*::before,
*::after {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: "Poppins", sans-serif;
  font-size: 16px;
  line-height: 1.5;
  color: var(--dark-color);
  padding-top: 70px; /* Compensation pour la navbar fixe */
}

.container {
  /* width: 90%;
  max-width: 1200px; */
  margin: 0 auto;
  padding: 0 15px;
}

/* Utilitaires */
.flex {
  display: flex;
}

.flex-col {
  flex-direction: column;
}

.items-center {
  align-items: center;
}

.justify-between {
  justify-content: space-between;
}

.text-center {
  text-align: center;
}

/* Navigation - CORRIGÉ POUR ÊTRE FIXE */
.navbar {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  z-index: 1000;
  background-color: #fff;
  box-shadow: 0 2px 5px rgba(0, 0, 0, 0.1);
  padding: 15px 30px;
  display: flex;
  justify-content: space-between;
  align-items: center;
  height: 70px;
}

/* Logo de la navbar */
.navbar .logo {
  font-size: 24px;
  font-weight: bold;
  color: #333;
  text-transform: uppercase;
}

.logo img {
  height: 60px;
  transition: var(--transition);
}

.logo img:hover {
  transform: scale(1.05);
}

.navbar-profile-img {
  width: 35px;
  height: 35px;
  border-radius: 50%;
  object-fit: cover;
  border: 2px solid #fff;
  box-shadow: 0 0 5px rgba(0,0,0,0.1);
  transition: transform 0.3s ease;
}
.navbar-profile-img:hover {
  transform: scale(1.05);
}


/* Menu de navigation */
.navbar ul {
  list-style: none;
  display: flex;
  gap: 20px;
  margin: 0;
}

.navbar ul li {
  padding: 10px;
}

.navbar ul li a {
  text-decoration: none;
  color: #333;
  font-size: 16px;
  font-weight: 500;
  transition: color 0.3s;
}

.navbar ul li a:hover {
  color: #ff0000;
}

/* Boutons supplémentaires (ex : panier, connexion) */
.navbar .auth-buttons {
  display: flex;
  gap: 15px;
}

.navbar .auth-buttons a {
  text-decoration: none;
  color: #333;
  font-size: 16px;
  font-weight: 500;
  transition: color 0.3s;
}

.navbar .auth-buttons a:hover {
  color: #007bff;
}

.navbar-container {
  display: flex;
  justify-content: space-between;
  width: 100%;
}

.nav-links,
.nav-icons {
  list-style: none;
  display: flex;
  margin: 0;
  padding: 0;
}

.nav-links li {
  margin-left: 60px;
  position: relative;
}

.nav-links li::after {
  content: "";
  position: absolute;
  bottom: -5px;
  left: 0;
  width: 0;
  height: 2px;
  background-color: var(--primary-color);
  transition: var(--transition);
}

.nav-links li:hover::after {
  width: 100%;
}

.nav-icons li {
  margin-left: 35px;
  position: relative;
}

.nav-link {
  color: var(--dark-color);
  text-decoration: none;
  font-size: 17px;
  font-weight: 500;
  transition: var(--transition);
  letter-spacing: 0.5px;
}

.nav-link:hover {
  color: var(--primary-color);
}

.nav-icon {
  color: var(--dark-color);
  position: relative;
}

.nav-icon i,
.nav-link i {
  font-size: 22px;
  transition: var(--transition);
}

.nav-icon i:hover,
.nav-link i:hover {
  color: var(--primary-color);
  transform: scale(1.1);
}




.cart-badge {
  position: absolute;
  top: -8px;
  right: -8px;
  background-color: var(--primary-color);
  color: white;
  font-size: 10px;
  width: 18px;
  height: 18px;
  border-radius: 50%;
  display: flex;
  justify-content: center;
  align-items: center;
  font-weight: bold;
}

.mobile-menu-toggle {
  display: none;
  background: none;
  border: none;
  font-size: 24px;
  cursor: pointer;
  color: var(--dark-color);
}

/* Hero et carousel */
.home-header2,
.carousel-container {
  height: 600px;
  width: 90%;
  margin: 20px auto;
  position: relative;
  overflow: hidden;
  border-radius: var(--border-radius);
  box-shadow: var(--shadow-sm);
}

.carousel-container {
  border-radius: 15px;
  overflow: hidden;
}

.carousel-inner img,
.carousel-item img {
  border-radius: 0; /* On garde le radius seulement sur le conteneur */
  width: 100%;
  height: auto;
  object-fit: cover;
}


#carouselExample,
.carousel-inner,
#carousel-item img {
  height: 100%;
  width: 100%;
  object-fit: cover;
}

.carousel-caption {
  position: absolute;
  bottom: 20%;
  left: 10%;
  text-align: left;
  max-width: 500px;
}

.carousel-caption h2 {
  font-size: 2.5rem;
  font-weight: 700;
  margin-bottom: 15px;
  color: var(--white-color);
  text-shadow: 0 2px 4px rgba(0, 0, 0, 0.3);
}

.carousel-caption p {
  font-size: 1.2rem;
  margin-bottom: 20px;
  color: var(--white-color);
  text-shadow: 0 2px 4px rgba(0, 0, 0, 0.3);
}

.btn {
  display: inline-block;
  padding: 12px 25px;
  border-radius: 30px;
  text-decoration: none;
  font-weight: 600;
  transition: var(--transition);
  border: none;
  cursor: pointer;
}

.btn-primary {
  background-color: var(--primary-color);
  color: var(--white-color);
}

.btn-primary:hover {
  background-color: #d62828;
  transform: translateY(-3px);
  box-shadow: 0 10px 20px rgba(0, 0, 0, 0.1);
}

.btn-light {
  background-color: var(--white-color);
  color: var(--dark-color);
}

.btn-light:hover {
  background-color: var(--primary-color);
  color: var(--white-color);
}

/* Titres de section */
.section-title {
  text-align: center;
  margin: 50px 0 30px;
  position: relative;
}

.section-title h2 {
  font-size: 32px;
  font-weight: 700;
  display: inline-block;
  position: relative;
  z-index: 1;
}

.section-title h2::after {
  content: "";
  position: absolute;
  bottom: -10px;
  left: 50%;
  transform: translateX(-50%);
  width: 80px;
  height: 3px;
  background-color: var(--primary-color);
}

.home-text p,
.home-text2 p {
  display: flex;
  justify-content: center;
  align-items: center;
  font-size: 28px;
  margin: 50px 0 30px;
  text-align: center;
  font-weight: 600;
  color: var(--dark-color);
}

/* === Formulaire d'inscription stylisé === */
.register-form {
  max-width: 600px;
  margin: 60px auto;
  padding: 40px 30px;
  background-color: #fff;
  border-radius: 15px;
  box-shadow: 0 8px 25px rgba(0, 0, 0, 0.1);
  animation: fadeInUp 0.6s ease;
}

.register-form h1 {
  text-align: center;
  margin-bottom: 30px;
  font-size: 32px;
  color: #d32f2f;
}

.register-form p {
  text-align: center;
  margin-bottom: 25px;
  font-size: 16px;
  color: #555;
}

.register-form label {
  display: block;
  margin-bottom: 8px;
  font-weight: 600;
  color: #333;
}

.register-form input[type="text"],
.register-form input[type="email"],
.register-form input[type="password"] {
  width: 100%;
  padding: 14px;
  margin-bottom: 20px;
  border: 1px solid #ddd;
  border-radius: 8px;
  font-size: 15px;
  background-color: #f9f9f9;
  transition: border-color 0.3s ease, background-color 0.3s ease;
}

.register-form input:focus {
  border-color: #d32f2f;
  background-color: #fff;
  outline: none;
}

.register-form button[type="submit"] {
  width: 100%;
  padding: 14px;
  background-color: #d32f2f;
  color: white;
  border: none;
  border-radius: 10px;
  font-size: 16px;
  font-weight: bold;
  text-transform: uppercase;
  cursor: pointer;
  transition: background-color 0.3s ease;
}

.register-form button:hover {
  background-color: #b71c1c;
}

.container > h1 {
  text-align: center;
  font-size: 32px;
  margin-bottom: 20px;
}


/* Animation à l’apparition */
@keyframes fadeInUp {
  from {
    opacity: 0;
    transform: translateY(20px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

/* === STYLE DE LA PAGE CGV === */
.content {
  max-width: 900px;
  margin: 80px auto;
  padding: 40px 30px;
  background-color: #fff;
  border-radius: 12px;
  box-shadow: 0 10px 25px rgba(0, 0, 0, 0.05);
  font-family: "Poppins", sans-serif;
  color: #333;
  animation: fadeIn 0.6s ease-in-out;
  counter-reset: section-counter;
}

.content h1 {
  text-align: center;
  font-size: 36px;
  margin-bottom: 50px;
  color: #d32f2f;
  border-bottom: 2px solid #eee;
  padding-bottom: 15px;
}

.content section {
  margin-bottom: 35px;
}

.content h2 {
  counter-increment: section-counter;
  position: relative;
  font-size: 24px;
  color: #d32f2f;
  margin-bottom: 12px;
  padding-left: 35px;
}

.content h2::before {
  content: counter(section-counter) ".";
  position: absolute;
  left: 0;
  top: 0;
  font-weight: bold;
  font-size: 24px;
  color: #555;
}

.content p {
  font-size: 16px;
  line-height: 1.8;
  color: #444;
  margin-bottom: 12px;
}

.content ul {
  padding-left: 40px;
  margin-bottom: 20px;
  list-style-type: disc;
}

.content li {
  font-size: 16px;
  color: #444;
  margin-bottom: 6px;
}

.content a {
  color: #1976d2;
  text-decoration: none;
  transition: color 0.3s ease;
}

.content a:hover {
  text-decoration: underline;
  color: #0d47a1;
}

/* Animation à l’entrée */
@keyframes fadeIn {
  from {
    opacity: 0;
    transform: translateY(20px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

/* Responsive */
@media (max-width: 768px) {
  .content {
    padding: 30px 20px;
  }

  .content h2 {
    font-size: 20px;
    padding-left: 28px;
  }

  .content h2::before {
    font-size: 20px;
  }

  .content p,
  .content li {
    font-size: 15px;
  }
}

/* === PAGE PANIER === */

.cart-title {
  text-align: center;
  font-size: 32px;
  margin: 50px 0 30px;
  color: #d32f2f;
}

.cart-container {
  max-width: 1000px;
  margin: 0 auto 80px;
  padding: 0 20px;
  background-color: #fff;
  border-radius: 12px;
  box-shadow: 0 8px 25px rgba(0, 0, 0, 0.05);
  overflow-x: auto;
}

.cart-table {
  width: 100%;
  border-collapse: collapse;
  margin-bottom: 30px;
}

.cart-table thead {
  background-color: #f8f8f8;
}

.cart-table th,
.cart-table td {
  padding: 15px 12px;
  text-align: center;
  border-bottom: 1px solid #eee;
  font-size: 16px;
}

.cart-product {
  display: flex;
  align-items: center;
  gap: 15px;
  text-align: left;
}

.cart-product img {
  width: 100px;
  height: auto;
  border-radius: 8px;
  object-fit: cover;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
}

.cart-table input[type="number"] {
  width: 60px;
  padding: 6px;
  text-align: center;
  border: 1px solid #ccc;
  border-radius: 6px;
  font-size: 15px;
}

.btn-remove {
  background: none;
  color: #d32f2f;
  font-size: 20px;
  cursor: pointer;
  text-decoration: none;
  transition: transform 0.2s ease;
}

.btn-remove:hover {
  transform: scale(1.2);
}

.cart-total {
  font-size: 18px;
  text-align: right;
  font-weight: 600;
  margin-top: 10px;
  margin-bottom: 30px;
  color: #444;
}

.btn-link {
  display: inline-block;
  padding: 14px 30px;
  background-color: #d32f2f;
  color: #fff;
  text-decoration: none;
  font-weight: 600;
  border-radius: 8px;
  transition: background-color 0.3s ease;
  text-align: center;
}

.btn-link:hover {
  background-color: #b71c1c;
}

.cart-empty {
  text-align: center;
  font-size: 18px;
  padding: 60px 0;
  color: #777;
}

/* Responsive */
@media (max-width: 768px) {
  .cart-product {
    flex-direction: column;

  }
}

/* Grilles de produits */
.product-grid,
.home-recommended-image,
.home-pack {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
  gap: 30px;
  margin: 30px auto;
  width: 90%;
}

.product-card {
  background-color: var(--white-color);
  border-radius: var(--border-radius);
  overflow: hidden;
  box-shadow: var(--shadow-sm);
  transition: var(--transition);
  position: relative;
}

.product-card:hover {
  transform: translateY(-5px);
  box-shadow: var(--shadow-md);
}

.product-image {
  overflow: hidden;
}

.product-image img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: var(--transition);
}

.product-card:hover .product-image img {
  transform: scale(1.05);
}

.product-info {
  padding: 15px;
}

.product-title {
  font-size: 18px;
  font-weight: 600;
  margin-bottom: 8px;
  color: var(--dark-color);
}

.product-category {
  font-size: 14px;
  color: var(--gray-color);
  margin-bottom: 10px;
}

.product-price {
  display: flex;
  align-items: center;
  margin-bottom: 15px;
}

.current-price {
  font-size: 20px;
  font-weight: 700;
  color: var(--dark-color);
}

.old-price {
  font-size: 16px;
  color: var(--gray-color);
  text-decoration: line-through;
  margin-left: 10px;
}

.product-rating {
  display: flex;
  margin-bottom: 15px;
}

.product-rating i {
  color: #ffc107;
  font-size: 14px;
  margin-right: 2px;
}

.product-actions {
  display: flex;
  justify-content: space-between;
}

.icon-btn {
  border: 1px solid var(--gray-color);
  border-radius: 50%;
  width: 40px;
  height: 40px;
  display: flex;
  justify-content: center;
  align-items: center;
  cursor: pointer;
  transition: var(--transition);
}

.icon-btn:hover {
  border-color: var(--primary-color);
  color: var(--white-color);
}

.badge {
  position: absolute;
  top: 10px;
  left: 0;
  background-color: var(--primary-color);
  color: var(--white-color);
  padding: 5px 10px;
  font-size: 12px;
  font-weight: 600;
  z-index: 1;
}

/* Images recommandées */
.home-recommended-image img,
.home-pack img {
  width: 100%;
  height: auto;
  max-height: 300px;
  object-fit: cover;
  border-radius: var(--border-radius);
  box-shadow: var(--shadow-sm);
  transition: var(--transition);
}

.home-recommended-image img:hover,
.home-pack img:hover {
  transform: scale(1.03);
}

/* Bannières promo */
.promo-banner {
  width: 90%;
  margin: 50px auto;
  position: relative;
  height: 300px;
  border-radius: var(--border-radius);
  overflow: hidden;
}

.promo-banner img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.promo-content {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  display: flex;
  flex-direction: column;
  justify-content: center;
  padding: 0 50px;
  background: linear-gradient(90deg, rgba(0, 0, 0, 0.7) 0%, rgba(0, 0, 0, 0.4) 50%, rgba(0, 0, 0, 0) 100%);
}

.promo-content h3 {
  font-size: 32px;
  font-weight: 700;
  color: var(--white-color);
  margin-bottom: 15px;
}

.promo-content p {
  font-size: 18px;
  color: var(--white-color);
  margin-bottom: 20px;
  max-width: 500px;
}

.footer {
  background-color: #000;
  color: white;
  padding: 50px 20px 20px;
  margin-top: 60px;
  font-family: 'Arial', sans-serif;
  width: 100% ;
}

.footer a {
  text-decoration: none;
  transition: color 0.3s ease;
}

.footer a:hover {
  color: #ff6659;
}

.footer-left {
  text-align: center;
  margin-bottom: 30px;
}

.footer-left img {
  max-width: 100px;
}

.footer-top {
  text-align: center;
  /* max-width: 800px; */
  margin: 0 auto 40px;
}

.footer-top p {
  margin-bottom: 15px;
  font-size: 16px;
  line-height: 1.6;
}

.footer-button {
  display: inline-block;
  background-color: #f44336;
  color: white;
  padding: 10px 20px;
  border-radius: 5px;
  font-weight: bold;
  transition: background 0.3s ease;
}

.footer-button:hover {
  background-color: #d32f2f;
}

.footer-middle {
  text-align: center;
  margin-bottom: 30px;
}

.footer-middle .logo {
  font-size: 24px;
  font-weight: bold;
  margin-bottom: 20px;
}

.footer-nav {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: 15px;
  margin-bottom: 20px;
}

.footer-nav a {
  font-size: 14px;
  color: #ccc;
}

.social-icons a {
  margin: 0 10px;
  font-size: 20px;
  color: white;
}

.footer-bottom {
  text-align: center;
  border-top: 1px solid #444;
  padding-top: 20px;
  font-size: 14px;
  color: #aaa;
}


.footer::before {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 5px;
  background: var(--gradient-primary);
}

.footer-container {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: 50px;
  max-width: 1200px;
  margin: 0 auto;
}

.footer-left {
  display: flex;
  flex-direction: column;
  align-items: center; /* Centrer le contenu */
  text-align: center; /* Centrer le texte */
}

.footer-left img {
  width: 180px;
  margin-bottom: 25px;
}

.footer-left p {
  font-size: 15px;
  line-height: 1.7;
  margin-bottom: 25px;
  color: #bbb;
  text-align: center; /* Ensure text is centered */
}

.footer-column h3 {
  font-size: 20px;
  font-weight: 600;
  margin-bottom: 25px;
  position: relative;
  padding-bottom: 12px;
  letter-spacing: 0.5px;
  color: #fff;
  text-align: center; /* Centrer les titres */
}

.footer-column h3::after {
  content: "";
  position: absolute;
  bottom: 0;
  left: 50%; /* Centrer la ligne de soulignement */
  transform: translateX(-50%);
  width: 50px;
  height: 3px;
  background-color: var(--primary-color);
}

.footer-links {
  list-style: none;
  padding: 0;
  margin: 0;
  text-align: center; /* Centrer les liens */
}

.footer-links li {
  margin-bottom: 15px;
}

.footer-links a {
  color: #bbb;
  text-decoration: none;
  font-size: 15px;
  transition: var(--transition);
  display: inline-block;
  position: relative;
  padding-left: 0;
}

.footer-links a:hover {
  color: var(--primary-color);
  padding-left: 8px;
}

.footer-links a::before {
  content: "›";
  position: absolute;
  left: -10px;
  opacity: 0;
  transition: var(--transition);
}

.footer-links a:hover::before {
  left: 0;
  opacity: 1;
}

.footer-contact {
  list-style: none;
  padding: 0;
  margin: 0 auto; /* Centrer la liste */
  max-width: fit-content;
}

.footer-contact li {
  display: flex;
  align-items: center; /* Changed from flex-start to center */
  justify-content: center; /* Added to center the content */
  margin-bottom: 18px;
  color: #bbb;
  font-size: 15px;
}

.footer-contact i {
  margin-right: 12px;
  color: var(--primary-color);
  font-size: 18px;
}

/* Icônes sociales */
.footer-socials {
  display: flex;
  gap: 15px;
  margin-top: 15px;
  justify-content: center; /* Centrer les icônes sociales */
}

.footer-socials a {
  width: 40px;
  height: 40px;
  background: #222;
  color: #fff;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: var(--transition);
  font-size: 18px;
}

.footer-socials a:hover {
  background-color: var(--primary-color);
  transform: translateY(-4px);
  box-shadow: 0 5px 15px rgba(230, 57, 70, 0.3);
}

/* Footer Bottom */
.footer-bottom {
  text-align: center;
  padding-top: 40px;
  margin-top: 50px;
  border-top: 1px solid #333;
  font-size: 14px;
  color: #777;
  width: 100%;
}

.footer-bottom a {
  color: #bbb;
  text-decoration: none;
  margin: 0 10px;
  transition: var(--transition);
  position: relative;
}

.footer-bottom a:hover {
  color: var(--primary-color);
}

.footer-bottom a::after {
  content: "";
  position: absolute;
  bottom: -3px;
  left: 0;
  width: 0;
  height: 1px;
  background-color: var(--primary-color);
  transition: var(--transition);
}

