/* === Section des Commentaires === */
.comments-section {
  max-width: 900px;
  margin: 60px auto;
  background-color: #fff;
  padding: 40px 30px;
  border-radius: 15px;
  box-shadow: 0 10px 30px rgba(0, 0, 0, 0.05);
}

.comments-section h3 {
  font-size: 26px;
  margin-bottom: 25px;
  text-align: center;
  color: #d32f2f;
  position: relative;
}

.comments-section h3::after {
  content: "";
  display: block;
  width: 60px;
  height: 3px;
  background-color: #d32f2f;
  margin: 10px auto 0;
  border-radius: 2px;
}

.comment {
  border-bottom: 1px solid #eee;
  padding: 20px 0;
}

.comment:last-child {
  border-bottom: none;
}

.comment-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.comment-author {
  font-weight: 600;
  color: #333;
}

.comment-date {
  font-size: 13px;
  color: #999;
}

.comment-rating i {
  color: #ffc107;
  margin-right: 2px;
  font-size: 16px;
}

.comment-text {
  margin-top: 10px;
  font-size: 15px;
  line-height: 1.6;
  color: #444;
}

/* === Formulaire d'ajout de commentaire === */
.add-comment-form {
  margin-top: 40px;
}

.add-comment-form h4 {
  font-size: 22px;
  color: #d32f2f;
  margin-bottom: 20px;
  text-align: center;
}

.add-comment-form textarea {
  width: 100%;
  padding: 15px;
  border-radius: 8px;
  border: 1px solid #ddd;
  font-size: 15px;
  resize: vertical;
  background-color: #f9f9f9;
  transition: border-color 0.3s ease;
  min-height: 120px;
}

.add-comment-form textarea:focus {
  border-color: #d32f2f;
  outline: none;
  background-color: #fff;
}

.add-comment-form .rating-stars {
  display: flex;
  justify-content: center;
  margin: 15px 0;
}

.add-comment-form .rating-stars i {
  font-size: 24px;
  cursor: pointer;
  color: #ccc;
  transition: color 0.3s ease;
}

.add-comment-form .rating-stars i.active {
  color: #ffc107;
}

.add-comment-form button {
  display: block;
  margin: 0 auto;
  background-color: #d32f2f;
  color: white;
  border: none;
  padding: 12px 30px;
  font-size: 16px;
  font-weight: 600;
  border-radius: 8px;
  cursor: pointer;
  transition: background 0.3s ease;
}

.add-comment-form button:hover {
  background-color: #b71c1c;
}


.review-card {
